dashboard.definition:
{
	"title": "StatefulSets",
	"description": "Detailed monitoring dashboard for Kubernetes StatefulSets with ordinal tracking, persistent volume monitoring, and pod identity management",
	"inputs": {
		"input_CcDqzLCH": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "logs_index_token",
				"selectFirstSearchResult": true
			},
			"title": "Event Logs Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_OneXu9jt"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"logs_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"logs_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_cluster_selector": {
			"dataSources": {
				"primary": "ds_cluster_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "cluster_token"
			},
			"title": "Cluster",
			"type": "input.dropdown"
		},
		"input_global_trp": {
			"options": {
				"defaultValue": "-60m@m,now",
				"token": "global_time"
			},
			"title": "Time Range",
			"type": "input.timerange"
		},
		"input_index_selector": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "index_token",
				"selectFirstSearchResult": true
			},
			"title": "Metrics Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_1GkKlAXJ"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"metrics_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"metrics_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_namespace_selector": {
			"dataSources": {
				"primary": "ds_namespace_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "namespace_token"
			},
			"title": "Namespace",
			"type": "input.dropdown"
		},
		"input_statefulset_selector": {
			"dataSources": {
				"primary": "ds_statefulset_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "statefulset_token"
			},
			"title": "StatefulSet",
			"type": "input.dropdown"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					},
					"refresh": "61s"
				}
			}
		}
	},
	"visualizations": {
		"viz_available_replicas": {
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"options": {
				"majorValue": "> primary | seriesByName('available') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Available"
			},
			"title": "Available Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_avg_cpu_usage": {
			"dataSources": {
				"primary": "ds_avg_cpu"
			},
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 3,
				"sparklineValues": "> primary | seriesByName('Avg_CPU_Core_Usage')",
				"trendValue": "> sparklineValues | delta(-2)",
				"unit": "c"
			},
			"title": "Avg CPU Usage",
			"type": "splunk.singlevalue"
		},
		"viz_avg_memory_usage": {
			"dataSources": {
				"primary": "ds_avg_memory"
			},
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('Avg_Memory_Usage(MB)')",
				"trendValue": "> sparklineValues | delta(-2)",
				"unit": "MB"
			},
			"title": "Avg Memory Usage",
			"type": "splunk.singlevalue"
		},
		"viz_container_status": {
			"dataSources": {
				"primary": "ds_container_status"
			},
			"description": "Individual container health within pods",
			"options": {
				"showInternalFields": false
			},
			"title": "Container Status by Pod",
			"type": "splunk.table"
		},
		"viz_cpu_per_pod": {
			"dataSources": {
				"primary": "ds_cpu_per_pod"
			},
			"description": "Individual pod CPU utilization",
			"options": {
				"legendDisplay": "right",
				"legendTruncation": "ellipsisEnd",
				"nullValueDisplay": "connect",
				"xField": "_time"
			},
			"title": "CPU Usage per Pod (%)",
			"type": "splunk.line"
		},
		"viz_cpu_requests_vs_usage": {
			"dataSources": {
				"primary": "ds_cpu_requests_vs_usage"
			},
			"description": "Resource allocation efficiency",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"cpu_core_usage": "#F5A800",
					"cpu_request": "#1E93C6"
				},
				"stackMode": "stacked100",
				"xField": "pod"
			},
			"title": "CPU: Requests vs Actual Usage",
			"type": "splunk.column"
		},
		"viz_deployment_events": {
			"dataSources": {
				"primary": "ds_statefulset_events"
			},
			"description": "Last 20 events related to this statefulset",
			"options": {
				"backgroundColor": "> table | seriesByName('Type') | matchValue(eventColorMap)",
				"eventColorMap": {
					"Error": "#D41F1F",
					"Normal": "#FFFFFF",
					"Warning": "#F5A800"
				},
				"showInternalFields": false
			},
			"title": "Recent StatefulSet Events",
			"type": "splunk.table"
		},
		"viz_deployment_health": {
			"dataSources": {
				"primary": "ds_statefulset_health"
			},
			"description": "Overall health based on replicas and pod status",
			"options": {
				"healthColorConfig": [
					{
						"color": "#D41F1F",
						"to": 70,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 95,
						"value": 70
					},
					{
						"color": "#118832",
						"value": 95
					}
				],
				"majorColor": "> majorValue | rangeValue(healthColorConfig)",
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 2,
				"sparklineValues": "> primary | seriesByName('Health_Percent')",
				"trendValue": "> sparklineValues | delta(-2)",
				"unit": "%"
			},
			"title": "StatefulSet Health Score",
			"type": "splunk.singlevalue"
		},
		"viz_desired_replicas": {
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"options": {
				"majorValue": "> primary | seriesByName('desired') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Desired"
			},
			"title": "Desired Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_memory_per_pod": {
			"dataSources": {
				"primary": "ds_memory_per_pod"
			},
			"description": "Individual pod memory consumption",
			"options": {
				"legendDisplay": "right",
				"legendTruncation": "ellipsisEnd",
				"nullValueDisplay": "connect",
				"xField": "_time"
			},
			"title": "Memory Usage per Pod (MB)",
			"type": "splunk.line"
		},
		"viz_memory_requests_vs_usage": {
			"dataSources": {
				"primary": "ds_memory_requests_vs_usage"
			},
			"description": "Resource allocation efficiency",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"memory_request_mb": "#1E93C6",
					"memory_usage_mb": "#F5A800"
				},
				"stackMode": "stacked100",
				"xField": "pod"
			},
			"title": "Memory: Requests vs Actual Usage (MB)",
			"type": "splunk.column"
		},
		"viz_network_io": {
			"dataSources": {
				"primary": "ds_network_io"
			},
			"description": "Aggregate network traffic for all pods",
			"options": {
				"legendDisplay": "bottom",
				"nullValueDisplay": "connect",
				"seriesColorsByField": {
					"rx_mb": "#1E93C6",
					"tx_mb": "#F5A800"
				},
				"xField": "_time"
			},
			"title": "Network I/O (MB/s)",
			"type": "splunk.line"
		},
		"viz_pod_age": {
			"dataSources": {
				"primary": "ds_pod_age"
			},
			"description": "How long pods have been running",
			"title": "Pod Age Analysis",
			"type": "splunk.table"
		},
		"viz_pod_restart_counts": {
			"dataSources": {
				"primary": "ds_pod_restarts"
			},
			"description": "Identify crashlooping pods",
			"options": {
				"legendDisplay": "off",
				"seriesColors": [
					"#D41F1F"
				],
				"xField": "pod",
				"yField": "restart_count"
			},
			"title": "Pod Restart Counts",
			"type": "splunk.column"
		},
		"viz_pod_status_table": {
			"context": {
				"RestartsColumnFormatEditorConfig": {
					"number": {
						"thousandSeparated": false,
						"unitPosition": "after"
					}
				},
				"RestartsRowBackgroundColorsEditorConfig": [
					{
						"to": 1,
						"value": "#118832"
					},
					{
						"from": 1,
						"to": 3,
						"value": "#669922"
					},
					{
						"from": 3,
						"to": 5,
						"value": "#CBA700"
					},
					{
						"from": 5,
						"to": 7,
						"value": "#D94E17"
					},
					{
						"from": 7,
						"value": "#D41F1F"
					}
				],
				"RestartsRowColorsEditorConfig": [
					"#ffffff"
				],
				"StatusColumnFormatEditorConfig": {
					"string": {
						"unitPosition": "after"
					}
				},
				"StatusRowBackgroundColorsEditorConfig": [
					{
						"match": "Failed",
						"value": "#D41F1F"
					},
					{
						"match": "Pending",
						"value": "#D97A0D"
					},
					{
						"match": "Succeeded",
						"value": "#9D9F0D"
					},
					{
						"match": "Running",
						"value": "#118832"
					}
				],
				"StatusRowColorsEditorConfig": [
					"#ffffff"
				]
			},
			"dataSources": {
				"primary": "ds_pod_status_table"
			},
			"description": "Current status of all pods in deployment",
			"options": {
				"backgroundColor": "> table | seriesByName('Status') | matchValue(statusColorMap)",
				"columnFormat": {
					"Restarts": {
						"align": "auto",
						"data": "> table | seriesByName(\"Restarts\") | formatByType(RestartsColumnFormatEditorConfig)",
						"headerAlign": "auto",
						"rowBackgroundColors": "> table | seriesByName(\"Restarts\") | rangeValue(RestartsRowBackgroundColorsEditorConfig)",
						"rowColors": "> table | seriesByName('Restarts') | pick(RestartsRowColorsEditorConfig)",
						"textOverflow": "break-word"
					},
					"Status": {
						"align": "auto",
						"data": "> table | seriesByName(\"Status\") | formatByType(StatusColumnFormatEditorConfig)",
						"headerAlign": "auto",
						"rowBackgroundColors": "> table | seriesByName(\"Status\") | matchValue(StatusRowBackgroundColorsEditorConfig)",
						"rowColors": "> table | seriesByName('Status') | pick(StatusRowColorsEditorConfig)",
						"textOverflow": "break-word"
					}
				},
				"statusColorMap": {
					"Failed": "#D41F1F",
					"Pending": "#F5A800",
					"Running": "#118832",
					"Unknown": "#999999"
				}
			},
			"title": "Pod Details",
			"type": "splunk.table"
		},
		"viz_pvc_status": {
			"context": {
				"volume_used__ColumnFormatEditorConfig": {
					"number": {
						"thousandSeparated": false,
						"unit": "%",
						"unitPosition": "after"
					}
				},
				"volume_used__RowBackgroundColorsEditorConfig": [
					{
						"to": 20,
						"value": "#118832"
					},
					{
						"from": 20,
						"to": 40,
						"value": "#669922"
					},
					{
						"from": 40,
						"to": 60,
						"value": "#CBA700"
					},
					{
						"from": 60,
						"to": 80,
						"value": "#D94E17"
					},
					{
						"from": 80,
						"value": "#D41F1F"
					}
				],
				"volume_used__RowColorsEditorConfig": [
					"#ffffff"
				]
			},
			"dataSources": {
				"primary": "ds_pvc_status"
			},
			"description": "PVC status for StatefulSet pods",
			"options": {
				"columnFormat": {
					"volume_used_%": {
						"align": "auto",
						"data": "> table | seriesByName(\"volume_used_%\") | formatByType(volume_used__ColumnFormatEditorConfig)",
						"headerAlign": "auto",
						"rowBackgroundColors": "> table | seriesByName(\"volume_used_%\") | rangeValue(volume_used__RowBackgroundColorsEditorConfig)",
						"rowColors": "> table | seriesByName('volume_used_%') | pick(volume_used__RowColorsEditorConfig)",
						"textOverflow": "break-word"
					}
				},
				"showInternalFields": false
			},
			"title": "Persistent Volume Claims",
			"type": "splunk.table"
		},
		"viz_ready_replicas": {
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"options": {
				"majorColor": "#118832",
				"majorValue": "> primary | seriesByName('ready') | lastPoint()",
				"numberPrecision": 0,
				"unit": "Ready"
			},
			"title": "Ready Replicas",
			"type": "splunk.singlevalue"
		},
		"viz_replica_timeline": {
			"dataSources": {
				"primary": "ds_replica_timeline"
			},
			"description": "Desired vs Ready vs Available replicas",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"available": "#006D9C",
					"desired": "#1E93C6",
					"ready": "#118832"
				},
				"xField": "_time"
			},
			"title": "Replica Status Over Time",
			"type": "splunk.line"
		},
		"viz_resource_allocation": {
			"dataSources": {
				"primary": "ds_resource_allocation"
			},
			"description": "Total requests, limits, and usage",
			"options": {
				"showInternalFields": false
			},
			"title": "Resource Allocation Summary",
			"type": "splunk.table"
		},
		"viz_total_restarts": {
			"dataSources": {
				"primary": "ds_total_restarts"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(restartColorConfig)",
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"restartColorConfig": [
					{
						"color": "#118832",
						"to": 5,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 20,
						"value": 5
					},
					{
						"color": "#D41F1F",
						"value": 20
					}
				],
				"sparklineValues": "> primary | seriesByName('total_restarts')",
				"unit": "Restarts"
			},
			"title": "Total Pod Restarts",
			"type": "splunk.singlevalue"
		},
		"viz_unavailable_replicas": {
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(unavailableColorConfig)",
				"majorValue": "> primary | seriesByName('unavailable') | lastPoint()",
				"numberPrecision": 0,
				"unavailableColorConfig": [
					{
						"color": "#118832",
						"to": 1,
						"value": 0
					},
					{
						"color": "#D41F1F",
						"value": 1
					}
				],
				"unit": "Unavailable"
			},
			"title": "Updated Replicas",
			"type": "splunk.singlevalue"
		}
	},
	"dataSources": {
		"ds_avg_cpu": {
			"name": "Average CPU",
			"options": {
				"query": "| mstats p90(_value) as cpu_core_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=2m\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=StatefulSet Workload-Name=$statefulset_token$\n| timechart p90(cpu_core_usage) as Avg_CPU_Core_Usage span=2m\n| eval Avg_CPU_Core_Usage=round(Avg_CPU_Core_Usage,3)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_avg_memory": {
			"name": "Average Memory",
			"options": {
				"query": "| mstats avg(_value) as avg_memory_bytes WHERE index=$index_token$ metric_name=container.memory.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=2m | eval avg_memory_mb=avg_memory_bytes/1048576\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"StatefulSet\" Workload-Name=$statefulset_token$\n| timechart avg(avg_memory_mb) as Avg_Memory_Usage(MB)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_cluster_list": {
			"name": "Cluster List",
			"options": {
				"query": "| mcatalog values(k8s.cluster.name) as cluster WHERE index=$index_token$ | mvexpand cluster | rename cluster as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_container_status": {
			"name": "Container Status",
			"options": {
				"query": "| mstats latest(_value) as ready WHERE index=$index_token$ metric_name=k8s.container.ready k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.statefulset.name=$statefulset_token$ by k8s.pod.name, k8s.container.name | eval Status=if(ready==1, \"Ready\", \"Not Ready\") | rename k8s.pod.name as Pod, k8s.container.name as Container | table Pod, Container, Status | sort Pod, Container",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
